import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { api, setSignupComplete } from "../api";
import { DISPOSABLE_EMAIL_ERROR, isDisposableEmail } from "../utils/emailValidation";
import "../styles/auth.css";

export default function Signup() {
  const navigate = useNavigate();
  const [fullName, setFullName] = useState("");
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [mobileNumber, setMobileNumber] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [verificationCode, setVerificationCode] = useState("");
  const [pendingEmail, setPendingEmail] = useState("");
  const [otpStep, setOtpStep] = useState(false);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSignup = async (e) => {
    e.preventDefault();

    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    if (password.length < 6) {
      setError("Password must be at least 6 characters.");
      return;
    }

    if (isDisposableEmail(email)) {
      setError(DISPOSABLE_EMAIL_ERROR);
      return;
    }

    try {
      setError("");
      setMessage("");
      setLoading(true);
      const res = await api.post("/auth/signup/", {
        full_name: fullName,
        username,
        email,
        mobile_number: mobileNumber,
        password,
        confirm_password: confirmPassword,
      });
      setSignupComplete();
      setLoading(false);
      setPendingEmail(email);
      setOtpStep(true);
      setMessage(res.data?.detail || "Signup successful. Check your inbox for the OTP.");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Signup failed. Please try again.");
    }
  };

  const handleVerifyEmail = async (e) => {
    e.preventDefault();

    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/verify-email-otp/", {
        email: pendingEmail || email,
        code: verificationCode,
      });
      setLoading(false);
      setMessage("Email verified successfully. You can sign in now.");
      navigate("/login");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to verify email OTP.");
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="auth-header">
          <h1>Create Account</h1>
          <p>Create your account with a real email, then sign in to continue.</p>
        </div>

        {!otpStep ? (
          <form onSubmit={handleSignup} className="auth-form">
            <div className="form-group">
              <label htmlFor="fullName">Full Name</label>
              <input
                id="fullName"
                type="text"
                placeholder="Enter your full name"
                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                required
              />
              <div className="input-focus"></div>
            </div>

          <div className="form-group">
            <label htmlFor="username">Username</label>
            <input
              id="username"
              type="text"
              placeholder="Choose a username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

            <div className="form-group">
              <label htmlFor="mobileNumber">Mobile Number</label>
              <input
                id="mobileNumber"
                type="tel"
                placeholder="Enter mobile number"
                value={mobileNumber}
                onChange={(e) => setMobileNumber(e.target.value)}
                required
              />
              <div className="input-focus"></div>
            </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type="password"
              placeholder="Create a password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          <div className="form-group">
            <label htmlFor="confirmPassword">Confirm Password</label>
            <input
              id="confirmPassword"
              type="password"
              placeholder="Confirm your password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          {error && <div className="error-box">{error}</div>}
          {message && <div className="success-message">{message}</div>}

          <button type="submit" className="btn-signup" disabled={loading}>
            {loading ? "Creating Account..." : "Sign Up"}
          </button>
          </form>
        ) : (
          <form onSubmit={handleVerifyEmail} className="auth-form">
            <div className="form-group">
              <label htmlFor="verificationCode">Email OTP</label>
              <input
                id="verificationCode"
                type="text"
                placeholder="Enter the code sent to your email"
                value={verificationCode}
                onChange={(e) => setVerificationCode(e.target.value)}
                required
              />
              <div className="input-focus"></div>
            </div>

            {error && <div className="error-box">{error}</div>}
            {message && <div className="success-message">{message}</div>}

            <button type="submit" className="btn-signup" disabled={loading}>
              {loading ? "Verifying..." : "Verify Email"}
            </button>

            <button
              type="button"
              className="btn-login"
              style={{ marginTop: 12 }}
              onClick={() => navigate("/login")}
            >
              Go to Sign In
            </button>
          </form>
        )}

        <div className="auth-footer">
          <p>Temporary/disposable emails are not allowed.</p>
          <p>Already have an account? <Link to="/login" className="auth-link">Sign In</Link></p>
        </div>
      </div>
    </div>
  );
}
